tasks.description:
Create `apps/server/src/services/builtin-extensions/ensure-marketplace.ts` — a startup helper that installs or updates the built-in Dork Hub extension on server boot. It mirrors the pattern in `apps/server/src/services/mesh/ensure-dorkbot.ts`.

Behavior (three paths):
1. **Fresh install** — extension not present in the extension manager registry → read `extension.json` from `apps/server/src/builtin-extensions/marketplace/`, validate it against the manifest schema, and register it with the `ExtensionManager`.
2. **Upgrade** — extension present but version differs → re-register with the new manifest.
3. **Already correct** — no-op.

File: `apps/server/src/services/builtin-extensions/ensure-marketplace.ts`

```typescript
import fs from 'fs/promises';
import path from 'path';
import { fileURLToPath } from 'url';
import { parseExtensionManifest } from '@dorkos/extension-api/manifest-schema';
import type { ExtensionManager } from '../extensions/extension-manager.js';
import { logger } from '../../lib/logger.js';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const BUILTIN_EXT_DIR = path.resolve(
  __dirname,
  '../../builtin-extensions/marketplace'
);
const EXTENSION_ID = '@dorkos-builtin/marketplace';

/**
 * Ensure the Dork Hub built-in extension is registered.
 *
 * Runs on server startup. Mirrors `ensureDorkBot` — three paths:
 * 1. Fresh install: register from `apps/server/src/builtin-extensions/marketplace/extension.json`
 * 2. Upgrade: version mismatch → re-register with updated manifest
 * 3. Already correct: no-op
 *
 * @param extensionManager - The running ExtensionManager instance
 */
export async function ensureBuiltinMarketplaceExtension(
  extensionManager: ExtensionManager
): Promise<void> {
  const manifestPath = path.join(BUILTIN_EXT_DIR, 'extension.json');
  const raw = await fs.readFile(manifestPath, 'utf-8');
  const manifest = parseExtensionManifest(JSON.parse(raw));

  const existing = extensionManager.getById(EXTENSION_ID);

  if (existing && existing.version === manifest.version) {
    logger.debug('[BuiltinExtensions] Dork Hub already registered at version %s', manifest.version);
    return;
  }

  if (existing) {
    await extensionManager.unregister(EXTENSION_ID);
    logger.info('[BuiltinExtensions] Upgrading Dork Hub from %s to %s', existing.version, manifest.version);
  } else {
    logger.info('[BuiltinExtensions] Installing Dork Hub %s', manifest.version);
  }

  await extensionManager.registerBuiltin({
    manifest,
    sourceDir: BUILTIN_EXT_DIR,
  });
}
```

Notes:
- If `ExtensionManager` doesn't expose `getById`, `unregister`, or `registerBuiltin` as shown, inspect `apps/server/src/services/extensions/extension-manager.ts` (already modified in this branch) and adapt to the actual API. Do not invent methods that don't exist — file an issue/todo in the task if the API needs extension.
- The helper must not throw on "already correct" — it's idempotent.
- Must use `logger` from `apps/server/src/lib/logger.js`, not `console`.
- Must NOT use `os.homedir()` (violates `.claude/rules/dork-home.md`). The built-in extension source lives in the installed server package directory, resolved via `import.meta.url`.

Acceptance criteria:
- [ ] File exists at `apps/server/src/services/builtin-extensions/ensure-marketplace.ts`
- [ ] Function signature matches and is exported
- [ ] TSDoc present on the exported function
- [ ] Uses `parseExtensionManifest` from `@dorkos/extension-api/manifest-schema` (will throw on invalid manifest)
- [ ] Logs at `info` on install/upgrade and `debug` on no-op
- [ ] No `os.homedir()` usage

Create `apps/server/src/services/builtin-extensions/__tests__/ensure-marketplace.test.ts` with Vitest coverage for all three code paths in the ensure helper (fresh install, upgrade, no-op).

Test scenarios:

1. **Fresh install** — `extensionManager.getById()` returns `null` → verifies `registerBuiltin()` is called with the parsed manifest and correct `sourceDir`, and `logger.info` logs "Installing Dork Hub <version>".

2. **Upgrade** — `getById()` returns an existing extension with a different `version` → verifies `unregister(EXTENSION_ID)` is called before `registerBuiltin()`, and `logger.info` logs "Upgrading Dork Hub from X to Y".

3. **Already correct** — `getById()` returns an existing extension with the SAME `version` → verifies neither `unregister` nor `registerBuiltin` are called, and `logger.debug` logs "already registered".

4. **Invalid manifest** — stub `fs.readFile` to return malformed JSON or a manifest missing required fields → verifies the helper throws and the error message includes helpful context (let `parseExtensionManifest` throw naturally — don't swallow).

Test skeleton:

```typescript
import { describe, it, expect, vi, beforeEach } from 'vitest';
import fs from 'fs/promises';
import { ensureBuiltinMarketplaceExtension } from '../ensure-marketplace.js';
import { logger } from '../../../lib/logger.js';

vi.mock('fs/promises');
vi.mock('../../../lib/logger.js', () => ({
  logger: {
    info: vi.fn(),
    debug: vi.fn(),
    warn: vi.fn(),
    error: vi.fn(),
  },
}));

describe('ensureBuiltinMarketplaceExtension', () => {
  let mockExtensionManager: {
    getById: ReturnType<typeof vi.fn>;
    unregister: ReturnType<typeof vi.fn>;
    registerBuiltin: ReturnType<typeof vi.fn>;
  };

  const validManifest = {
    id: '@dorkos-builtin/marketplace',
    name: 'Dork Hub',
    version: '1.0.0',
    description: 'Browse, install, and manage DorkOS marketplace packages.',
    author: 'DorkOS',
    builtin: true,
    entry: { client: './index.ts', server: './server.ts' },
    slots: {
      'sidebar.tabs': [
        { id: 'dork-hub', label: 'Dork Hub', icon: 'store', route: '/marketplace', priority: 20 },
      ],
    },
  };

  beforeEach(() => {
    vi.clearAllMocks();
    mockExtensionManager = {
      getById: vi.fn(),
      unregister: vi.fn().mockResolvedValue(undefined),
      registerBuiltin: vi.fn().mockResolvedValue(undefined),
    };
    vi.mocked(fs.readFile).mockResolvedValue(JSON.stringify(validManifest));
  });

  it('registers extension on fresh install', async () => {
    mockExtensionManager.getById.mockReturnValue(null);
    await ensureBuiltinMarketplaceExtension(mockExtensionManager as any);
    expect(mockExtensionManager.registerBuiltin).toHaveBeenCalledOnce();
    expect(mockExtensionManager.unregister).not.toHaveBeenCalled();
    expect(logger.info).toHaveBeenCalledWith(expect.stringContaining('Installing Dork Hub'), '1.0.0');
  });

  it('upgrades extension when version differs', async () => {
    mockExtensionManager.getById.mockReturnValue({ id: '@dorkos-builtin/marketplace', version: '0.9.0' });
    await ensureBuiltinMarketplaceExtension(mockExtensionManager as any);
    expect(mockExtensionManager.unregister).toHaveBeenCalledWith('@dorkos-builtin/marketplace');
    expect(mockExtensionManager.registerBuiltin).toHaveBeenCalledOnce();
  });

  it('is a no-op when version matches', async () => {
    mockExtensionManager.getById.mockReturnValue({ id: '@dorkos-builtin/marketplace', version: '1.0.0' });
    await ensureBuiltinMarketplaceExtension(mockExtensionManager as any);
    expect(mockExtensionManager.registerBuiltin).not.toHaveBeenCalled();
    expect(mockExtensionManager.unregister).not.toHaveBeenCalled();
    expect(logger.debug).toHaveBeenCalled();
  });

  it('throws on invalid manifest', async () => {
    vi.mocked(fs.readFile).mockResolvedValue('{"name": "bad"}');
    mockExtensionManager.getById.mockReturnValue(null);
    await expect(ensureBuiltinMarketplaceExtension(mockExtensionManager as any)).rejects.toThrow();
  });
});
```

