Create TanStack Query mutation hooks in `apps/client/src/layers/entities/marketplace/model/` for install, uninstall, update, add source, and remove source. Each mutation must invalidate the relevant query keys on success.

Files to create:

1. `use-install-package.ts`:

```typescript
import { useMutation, useQueryClient } from '@tanstack/react-query';
import type { InstallOptions, InstallResult } from '@dorkos/marketplace';
import { marketplaceMethods } from '@/layers/shared/lib/transport';

interface InstallArgs {
  name: string;
  options?: InstallOptions;
}

/**
 * Install a marketplace package. Invalidates installed + package-detail queries on success.
 */
export function useInstallPackage() {
  const queryClient = useQueryClient();
  return useMutation<InstallResult, Error, InstallArgs>({
    mutationFn: ({ name, options }) => marketplaceMethods.install(name, options),
    onSuccess: (_result, { name }) => {
      queryClient.invalidateQueries({ queryKey: ['marketplace-installed'] });
      queryClient.invalidateQueries({ queryKey: ['marketplace-package', name] });
      queryClient.invalidateQueries({ queryKey: ['marketplace-packages'] });
    },
  });
}
```

