/**
 * @vitest-environment jsdom
 */
import { describe, it, expect, vi, beforeEach } from 'vitest';
import { renderHook, waitFor } from '@testing-library/react';
import { QueryClient, QueryClientProvider } from '@tanstack/react-query';
import type { ReactNode } from 'react';
import { useMarketplacePackages } from '../model/use-marketplace-packages';
import { useInstallPackage } from '../model/use-install-package';

const mockListPackages = vi.fn();
const mockInstall = vi.fn();

vi.mock('@/layers/shared/lib/transport', () => ({
  marketplaceMethods: {
    listPackages: (...args: unknown[]) => mockListPackages(...args),
    install: (...args: unknown[]) => mockInstall(...args),
  },
}));

function createWrapper() {
  const queryClient = new QueryClient({
    defaultOptions: { queries: { retry: false }, mutations: { retry: false } },
  });
  return function Wrapper({ children }: { children: ReactNode }) {
    return <QueryClientProvider client={queryClient}>{children}</QueryClientProvider>;
  };
}

describe('useMarketplacePackages', () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  it('fetches packages successfully', async () => {
    mockListPackages.mockResolvedValue([
      { name: '@dorkos/code-reviewer', type: 'agent', displayName: 'Code Reviewer' },
    ]);
    const { result } = renderHook(() => useMarketplacePackages(), {
      wrapper: createWrapper(),
    });
    await waitFor(() => expect(result.current.isSuccess).toBe(true));
    expect(result.current.data).toHaveLength(1);
  });

  it('exposes error state on failure', async () => {
    mockListPackages.mockRejectedValue(new Error('Network down'));
    const { result } = renderHook(() => useMarketplacePackages(), {
      wrapper: createWrapper(),
    });
    await waitFor(() => expect(result.current.isError).toBe(true));
  });
});

describe('useInstallPackage', () => {
  beforeEach(() => vi.clearAllMocks());

  it('installs a package and returns result', async () => {
    mockInstall.mockResolvedValue({ installed: true, name: '@dorkos/code-reviewer' });
    const { result } = renderHook(() => useInstallPackage(), { wrapper: createWrapper() });
    result.current.mutate({ name: '@dorkos/code-reviewer' });
    await waitFor(() => expect(result.current.isSuccess).toBe(true));
    expect(mockInstall).toHaveBeenCalledWith('@dorkos/code-reviewer', undefined);
  });
});
