Create `apps/client/src/layers/features/marketplace/model/dork-hub-store.ts` — a Zustand store for Dork Hub UI state. This matches the Zustand pattern already used elsewhere in the client.

State shape:

```typescript
import { create } from 'zustand';
import type { MarketplacePackageEntry } from '@dorkos/marketplace';

export type DorkHubTypeFilter = 'all' | 'agent' | 'plugin' | 'skill-pack' | 'adapter';
export type DorkHubSort = 'featured' | 'popular' | 'recent' | 'name';

interface DorkHubFilters {
  type: DorkHubTypeFilter;
  category: string | null;
  search: string;
  sort: DorkHubSort;
}

interface DorkHubState {
  filters: DorkHubFilters;
  /** Currently-open package in the detail sheet (null = sheet closed). */
  detailPackage: MarketplacePackageEntry | null;
  /** Package pending the install confirmation dialog. */
  installConfirmPackage: MarketplacePackageEntry | null;

  setTypeFilter: (type: DorkHubTypeFilter) => void;
  setCategoryFilter: (category: string | null) => void;
  setSearch: (search: string) => void;
  setSort: (sort: DorkHubSort) => void;
  resetFilters: () => void;

  openDetail: (pkg: MarketplacePackageEntry) => void;
  closeDetail: () => void;

  openInstallConfirm: (pkg: MarketplacePackageEntry) => void;
  closeInstallConfirm: () => void;
}

const INITIAL_FILTERS: DorkHubFilters = {
  type: 'all',
  category: null,
  search: '',
  sort: 'featured',
};

/**
 * Zustand store for Dork Hub UI state — filters, detail sheet, install confirmation.
 * Server state lives in TanStack Query (see `entities/marketplace`).
 */
export const useDorkHubStore = create<DorkHubState>((set) => ({
  filters: INITIAL_FILTERS,
  detailPackage: null,
  installConfirmPackage: null,

  setTypeFilter: (type) => set((s) => ({ filters: { ...s.filters, type } })),
  setCategoryFilter: (category) => set((s) => ({ filters: { ...s.filters, category } })),
  setSearch: (search) => set((s) => ({ filters: { ...s.filters, search } })),
  setSort: (sort) => set((s) => ({ filters: { ...s.filters, sort } })),
  resetFilters: () => set({ filters: INITIAL_FILTERS }),

  openDetail: (pkg) => set({ detailPackage: pkg }),
  closeDetail: () => set({ detailPackage: null }),

  openInstallConfirm: (pkg) => set({ installConfirmPackage: pkg }),
  closeInstallConfirm: () => set({ installConfirmPackage: null }),
}));
```

