Create pure utility modules in `apps/client/src/layers/features/marketplace/lib/` used by the UI components.

1. `package-filter.ts` — filters an array of `MarketplacePackageEntry` by type, category, and search text. Case-insensitive search matches name, displayName, description, keywords.

```typescript
import type { MarketplacePackageEntry } from '@dorkos/marketplace';
import type { DorkHubTypeFilter } from '../model/dork-hub-store';

interface FilterCriteria {
  type: DorkHubTypeFilter;
  category: string | null;
  search: string;
}

/**
 * Filter a list of marketplace packages by type, category, and search text.
 * Search is case-insensitive and matches name, displayName, description, and keywords.
 */
export function filterPackages(
  packages: MarketplacePackageEntry[],
  criteria: FilterCriteria
): MarketplacePackageEntry[] {
  const needle = criteria.search.trim().toLowerCase();
  return packages.filter((pkg) => {
    if (criteria.type !== 'all' && pkg.type !== criteria.type) return false;
    if (criteria.category && pkg.category !== criteria.category) return false;
    if (!needle) return true;
    const haystack = [
      pkg.name,
      pkg.displayName ?? '',
      pkg.description ?? '',
      ...(pkg.keywords ?? []),
    ]
      .join(' ')
      .toLowerCase();
    return haystack.includes(needle);
  });
}
```

2. `package-sort.ts` — sorts filtered packages by the chosen sort order.

```typescript
import type { MarketplacePackageEntry } from '@dorkos/marketplace';
import type { DorkHubSort } from '../model/dork-hub-store';

/**
 * Sort packages by the chosen Dork Hub sort order.
 * - featured: featured packages first, then by name
 * - popular: by install count descending (falls back to name)
 * - recent: by updatedAt descending
 * - name: alphabetical
 */
export function sortPackages(
  packages: MarketplacePackageEntry[],
  sort: DorkHubSort
): MarketplacePackageEntry[] {
  const copy = [...packages];
  switch (sort) {
    case 'featured':
      return copy.sort((a, b) => {
        const af = a.featured ? 1 : 0;
        const bf = b.featured ? 1 : 0;
        if (af !== bf) return bf - af;
        return (a.displayName ?? a.name).localeCompare(b.displayName ?? b.name);
      });
    case 'popular':
      return copy.sort((a, b) => (b.installCount ?? 0) - (a.installCount ?? 0));
    case 'recent':
      return copy.sort(
        (a, b) => new Date(b.updatedAt ?? 0).getTime() - new Date(a.updatedAt ?? 0).getTime()
      );
    case 'name':
      return copy.sort((a, b) =>
        (a.displayName ?? a.name).localeCompare(b.displayName ?? b.name)
      );
  }
}
```

3. `format-permissions.ts` — formats a `PermissionPreview` into a human-readable structure grouped by severity. Used by `PermissionPreviewSection` and `InstallConfirmationDialog`.

```typescript
import type { PermissionPreview } from '@dorkos/marketplace';

export interface FormattedPermission {
  icon: string;
  label: string;
  description?: string;
  severity?: 'info' | 'warning' | 'error';
}

export interface FormattedPermissionGroups {
  effects: FormattedPermission[];
  secrets: FormattedPermission[];
  hosts: FormattedPermission[];
  dependencies: FormattedPermission[];
  conflicts: FormattedPermission[];
}

/**
 * Normalize a PermissionPreview into icon/label/severity groups ready for UI rendering.
 * Keeps the UI components free of formatting logic.
 */
export function formatPermissionPreview(
  preview: PermissionPreview
): FormattedPermissionGroups {
  return {
    effects: [
      ...(preview.fileChanges.length
        ? [{ icon: 'file', label: `${preview.fileChanges.length} files will be created` }]
        : []),
      ...preview.extensions.map((ext) => ({ icon: 'puzzle', label: `Register UI extension: ${ext.id}` })),
      ...preview.tasks.map((task) => ({
        icon: 'clock',
        label: `Schedule task: ${task.name}${task.cron ? ` (${task.cron})` : ''}`,
      })),
    ],
    secrets: preview.secrets.map((s) => ({
      icon: 'key',
      label: s.key + (s.required ? '' : ' (optional)'),
      description: s.description,
      severity: s.required ? 'warning' : 'info',
    })),
    hosts: preview.externalHosts.map((h) => ({ icon: 'globe', label: h })),
    dependencies: preview.requires.map((d) => ({
      icon: d.satisfied ? 'check' : 'alert',
      label: `${d.type}:${d.name}${d.version ? `@${d.version}` : ''}`,
      severity: d.satisfied ? 'info' : 'warning',
    })),
    conflicts: preview.conflicts.map((c) => ({
      icon: 'alert',
      label: c.description,
      severity: c.level === 'error' ? 'error' : 'warning',
    })),
  };
}
