import { useEffect, useState } from 'react';
import { Search } from 'lucide-react';
import { Input, Button, Label } from '@/layers/shared/ui';
import { cn } from '@/layers/shared/lib';
import { useDorkHubStore, type DorkHubTypeFilter } from '../model/dork-hub-store';

const TYPE_TABS: Array<{ value: DorkHubTypeFilter; label: string }> = [
  { value: 'all', label: 'All' },
  { value: 'agent', label: 'Agents' },
  { value: 'plugin', label: 'Plugins' },
  { value: 'skill-pack', label: 'Skills' },
  { value: 'adapter', label: 'Adapters' },
];

/**
 * Top section of Dork Hub: search input and type filter tabs.
 * Search is debounced 300ms before writing to the store.
 */
export function DorkHubHeader() {
  const storeSearch = useDorkHubStore((s) => s.filters.search);
  const activeType = useDorkHubStore((s) => s.filters.type);
  const setSearch = useDorkHubStore((s) => s.setSearch);
  const setType = useDorkHubStore((s) => s.setTypeFilter);

  const [localSearch, setLocalSearch] = useState(storeSearch);

  useEffect(() => {
    const t = setTimeout(() => setSearch(localSearch), 300);
    return () => clearTimeout(t);
  }, [localSearch, setSearch]);

  return (
    <header className="space-y-4">
      <div className="relative">
        <Label htmlFor="dork-hub-search" className="sr-only">
          Search packages
        </Label>
        <Search
          className="pointer-events-none absolute left-3 top-1/2 size-4 -translate-y-1/2 text-muted-foreground"
          aria-hidden
        />
        <Input
          id="dork-hub-search"
          value={localSearch}
          onChange={(e) => setLocalSearch(e.target.value)}
          placeholder="Search packages..."
          className="pl-9"
          data-testid="dork-hub-search"
        />
      </div>
      <div className="flex flex-wrap gap-1" role="tablist" aria-label="Package type">
        {TYPE_TABS.map((tab) => (
          <Button
            key={tab.value}
            variant={activeType === tab.value ? 'default' : 'ghost'}
            size="sm"
            role="tab"
            aria-selected={activeType === tab.value}
            onClick={() => setType(tab.value)}
            className={cn('rounded-full')}
          >
            {tab.label}
          </Button>
        ))}
      </div>
    </header>
  );
}
