import type { PermissionPreview } from '@dorkos/marketplace';
import { File, Puzzle, Clock, Key, Globe, Check, AlertTriangle } from 'lucide-react';
import { cn } from '@/layers/shared/lib';
import { formatPermissionPreview, type FormattedPermission } from '../lib/format-permissions';

const ICON_MAP: Record<string, React.ComponentType<{ className?: string }>> = {
  file: File,
  puzzle: Puzzle,
  clock: Clock,
  key: Key,
  globe: Globe,
  check: Check,
  alert: AlertTriangle,
};

function PermissionItem({ item }: { item: FormattedPermission }) {
  const Icon = ICON_MAP[item.icon] ?? File;
  const severityClass =
    item.severity === 'error'
      ? 'text-destructive'
      : item.severity === 'warning'
      ? 'text-amber-600 dark:text-amber-400'
      : 'text-muted-foreground';
  return (
    <li className={cn('flex items-start gap-2 text-sm', severityClass)}>
      <Icon className="mt-0.5 size-4 shrink-0" aria-hidden />
      <div className="flex-1">
        <span>{item.label}</span>
        {item.description && (
          <p className="text-xs text-muted-foreground">{item.description}</p>
        )}
      </div>
    </li>
  );
}

function Section({ title, items, tone }: { title: string; items: FormattedPermission[]; tone?: 'warning' }) {
  if (items.length === 0) return null;
  return (
    <section className="space-y-2">
      <h4
        className={cn(
          'text-xs font-semibold uppercase tracking-wider',
          tone === 'warning' ? 'text-amber-600 dark:text-amber-400' : 'text-muted-foreground'
        )}
      >
        {title}
      </h4>
      <ul className="space-y-1.5">
        {items.map((item, i) => (
          <PermissionItem key={i} item={item} />
        ))}
      </ul>
    </section>
  );
}

interface Props {
  preview: PermissionPreview;
}

/**
 * Human-readable permission preview showing what a package will do on install:
