```typescript
import { Sheet, SheetContent, SheetHeader, SheetTitle, SheetDescription, Button, Badge } from '@/layers/shared/ui';
import { Streamdown } from 'streamdown';
import {
  useMarketplacePackage,
  usePermissionPreview,
  useInstalledPackages,
  useUninstallPackage,
} from '@/layers/entities/marketplace';
import { useDorkHubStore } from '../model/dork-hub-store';
import { PackageTypeBadge } from './PackageTypeBadge';
import { PermissionPreviewSection } from './PermissionPreviewSection';

/**
 * Slide-in detail sheet shown when the user clicks a package card.
 * Fetches full package metadata, README, and permission preview. Provides
 * install / uninstall actions.
 */
export function PackageDetailSheet() {
  const pkg = useDorkHubStore((s) => s.detailPackage);
  const closeDetail = useDorkHubStore((s) => s.closeDetail);
  const openInstallConfirm = useDorkHubStore((s) => s.openInstallConfirm);

  const { data: detail, isLoading } = useMarketplacePackage(pkg?.name ?? null, pkg !== null);
  const { data: preview } = usePermissionPreview(pkg?.name ?? null, pkg !== null);
  const { data: installed } = useInstalledPackages();
  const uninstall = useUninstallPackage();

  const isInstalled = pkg && (installed ?? []).some((p) => p.name === pkg.name);

  return (
    <Sheet open={pkg !== null} onOpenChange={(open) => !open && closeDetail()}>
      <SheetContent side="right" className="w-full overflow-y-auto sm:max-w-xl">
        {pkg && (
          <>
            <SheetHeader>
              <div className="flex items-start justify-between gap-4">
                <div>
                  <SheetTitle>{pkg.displayName ?? pkg.name}</SheetTitle>
                  <SheetDescription>{pkg.description}</SheetDescription>
                </div>
                <PackageTypeBadge type={pkg.type} />
              </div>
              <div className="flex items-center gap-2 pt-2 text-xs text-muted-foreground">
                {detail?.version && <Badge variant="outline">v{detail.version}</Badge>}
                {detail?.author && <span>by {detail.author}</span>}
              </div>
            </SheetHeader>

            <div className="mt-6 space-y-6">
              {preview && (
                <div>
                  <h3 className="mb-3 text-sm font-semibold">Permissions</h3>
                  <PermissionPreviewSection preview={preview} />
                </div>
              )}

              {detail?.readme && (
                <div>
                  <h3 className="mb-3 text-sm font-semibold">README</h3>
                  <div className="prose prose-sm dark:prose-invert max-w-none">
                    <Streamdown>{detail.readme}</Streamdown>
                  </div>
                </div>
              )}

              {isLoading && <p className="text-sm text-muted-foreground">Loading details...</p>}
            </div>

            <div className="sticky bottom-0 mt-6 flex gap-2 border-t bg-background/95 py-4 backdrop-blur">
              <Button variant="ghost" onClick={closeDetail} className="flex-1">
                Close
              </Button>
              {isInstalled ? (
                <Button
                  variant="outline"
                  disabled={uninstall.isPending}
                  onClick={() => uninstall.mutate({ name: pkg.name })}
                  className="flex-1"
                >
                  {uninstall.isPending ? 'Uninstalling...' : 'Uninstall'}
                </Button>
              ) : (
                <Button onClick={() => openInstallConfirm(pkg)} className="flex-1">
                  Install
                </Button>
              )}
            </div>
          </>
        )}
      </SheetContent>
    </Sheet>
  );
}
