Create `apps/client/src/layers/features/marketplace/ui/InstallConfirmationDialog.tsx` — the modal confirmation dialog shown before install. Reads the pending package from `useDorkHubStore.installConfirmPackage`, fetches the permission preview, and on confirm calls `useInstallPackage`.

```typescript
import { AlertDialog, AlertDialogContent, AlertDialogHeader, AlertDialogTitle, AlertDialogDescription, AlertDialogFooter, Button } from '@/layers/shared/ui';
import { useInstallPackage, usePermissionPreview } from '@/layers/entities/marketplace';
import { useDorkHubStore } from '../model/dork-hub-store';
import { PermissionPreviewSection } from './PermissionPreviewSection';
import { useEffect } from 'react';
import { toast } from 'sonner'; // or whichever toast lib the project uses

/**
 * Blocking modal confirmation before a marketplace install. Shows the full
 * permission preview and requires an explicit "Install" click. Triggers the
 * install mutation on confirm and shows a toast on success/failure.
 */
export function InstallConfirmationDialog() {
  const pkg = useDorkHubStore((s) => s.installConfirmPackage);
  const close = useDorkHubStore((s) => s.closeInstallConfirm);
  const install = useInstallPackage();
  const { data: preview, isLoading: previewLoading } = usePermissionPreview(pkg?.name ?? null, pkg !== null);

  useEffect(() => {
    if (install.isSuccess) {
      toast.success(`Installed ${pkg?.displayName ?? pkg?.name}`);
      close();
      install.reset();
    }
    if (install.isError) {
      toast.error(`Install failed: ${install.error?.message ?? 'Unknown error'}`);
      install.reset();
    }
  }, [install.isSuccess, install.isError]);

  const hasBlockingConflicts =
    preview?.conflicts.some((c) => c.level === 'error') ?? false;

  return (
    <AlertDialog open={pkg !== null} onOpenChange={(open) => !open && close()}>
      <AlertDialogContent className="max-h-[85vh] overflow-y-auto sm:max-w-2xl">
        {pkg && (
          <>
            <AlertDialogHeader>
              <AlertDialogTitle>Install {pkg.displayName ?? pkg.name}?</AlertDialogTitle>
              <AlertDialogDescription>
                Review what this package will do before installing.
              </AlertDialogDescription>
            </AlertDialogHeader>

            <div className="my-4">
              {previewLoading && <p className="text-sm text-muted-foreground">Loading preview...</p>}
              {preview && <PermissionPreviewSection preview={preview} />}
            </div>

            <AlertDialogFooter>
              <Button variant="ghost" onClick={close} disabled={install.isPending}>
                Cancel
              </Button>
              <Button
                onClick={() => install.mutate({ name: pkg.name })}
                disabled={install.isPending || hasBlockingConflicts || previewLoading}
              >
                {install.isPending ? 'Installing...' : hasBlockingConflicts ? 'Cannot install (conflicts)' : 'Install'}
              </Button>
            </AlertDialogFooter>
          </>
        )}
      </AlertDialogContent>
    </AlertDialog>
  );
}
```

Notes:
- Uses `AlertDialog` from `shared/ui` (shadcn primitive)
- Blocks install if there are error-level conflicts
- Toast integration: use whichever toast lib the project already ships. Check `apps/client/src/layers/shared/ui/sonner.tsx` or similar — if `sonner` is used, import from there; otherwise match the existing pattern.
- Resets mutation after success/error to prevent repeated toasts

