- Alternatively, create a `useInstallWithToast()` hook that wraps `useInstallPackage` and fires the toasts internally

Preferred: the hook approach keeps components slim.

```typescript
// apps/client/src/layers/features/marketplace/model/use-install-with-toast.ts
import { useEffect } from 'react';
import { useInstallPackage } from '@/layers/entities/marketplace';
import { toast } from 'sonner';

/**
 * Wrapper around useInstallPackage that shows a pending toast during install
 * and a success/error toast on completion. Also exposes a "Configure secrets"
 * action on success (opens the existing secrets settings UI).
 */
export function useInstallWithToast() {
  const install = useInstallPackage();

  useEffect(() => {
    if (install.isPending && install.variables) {
      const id = toast.loading(`Installing ${install.variables.name}...`);
      return () => toast.dismiss(id);
    }
  }, [install.isPending, install.variables]);

  useEffect(() => {
    if (install.isSuccess && install.variables) {
      toast.success(`Installed ${install.variables.name}`, {
        action: {
          label: 'Configure secrets',
          onClick: () => {
            // Navigate to settings with ?package=<name>
            window.location.hash = `#/settings/secrets?package=${encodeURIComponent(install.variables.name)}`;
          },
        },
      });
      install.reset();
    }
    if (install.isError) {
      toast.error(`Install failed: ${install.error?.message ?? 'Unknown error'}`);
      install.reset();
    }
  }, [install.isSuccess, install.isError]);

  return install;
}
```

