Create `apps/client/src/layers/features/marketplace/ui/InstalledPackagesView.tsx` — the "Manage Installed" surface that lists currently-installed packages with update and uninstall actions.

```typescript
import { useInstalledPackages, useUninstallPackage, useUpdatePackage } from '@/layers/entities/marketplace';
import { Button, Badge } from '@/layers/shared/ui';
import { PackageTypeBadge } from './PackageTypeBadge';
import { PackageLoadingSkeleton } from './PackageLoadingSkeleton';
import { PackageEmptyState } from './PackageEmptyState';
import { AlertTriangle, Trash2, RefreshCw } from 'lucide-react';
import { useState } from 'react';

/**
 * "Manage Installed" view listing all currently-installed marketplace packages
 * with update notifications and uninstall (with purge) actions.
 */
export function InstalledPackagesView() {
  const { data: installed, isLoading, error } = useInstalledPackages();
  const uninstall = useUninstallPackage();
  const update = useUpdatePackage();
  const [confirmPurgeFor, setConfirmPurgeFor] = useState<string | null>(null);

  if (isLoading) return <PackageLoadingSkeleton count={3} />;
  if (error) return <p className="text-sm text-destructive">Failed to load installed packages.</p>;
  if (!installed || installed.length === 0) {
    return (
      <PackageEmptyState
        title="No packages installed yet"
        description="Browse the marketplace to install your first package."
      />
    );
  }

  return (
    <div className="space-y-4">
      {installed.map((pkg) => (
        <div key={pkg.name} className="flex items-center justify-between rounded-xl border bg-card p-6">
          <div className="flex items-center gap-4">
            <div>
              <div className="flex items-center gap-2">
                <h3 className="text-sm font-semibold">{pkg.displayName ?? pkg.name}</h3>
                <PackageTypeBadge type={pkg.type} />
                <Badge variant="outline">v{pkg.version}</Badge>
              </div>
              <p className="text-xs text-muted-foreground">Installed from {pkg.source}</p>
            </div>
          </div>
          <div className="flex items-center gap-2">
            {pkg.updateAvailable && (
              <Button
                size="sm"
                variant="outline"
                onClick={() => update.mutate(pkg.name)}
                disabled={update.isPending}
              >
                <RefreshCw className="mr-1 size-3" />
                Update to v{pkg.latestVersion}
              </Button>
            )}
            <Button
              size="sm"
              variant="ghost"
              onClick={() => {
                if (confirmPurgeFor === pkg.name) {
                  uninstall.mutate({ name: pkg.name, purge: true });
                  setConfirmPurgeFor(null);
                } else {
                  setConfirmPurgeFor(pkg.name);
                  setTimeout(() => setConfirmPurgeFor(null), 3000);
                }
              }}
              className="text-destructive"
            >
              <Trash2 className="mr-1 size-3" />
              {confirmPurgeFor === pkg.name ? 'Confirm' : 'Uninstall'}
            </Button>
          </div>
        </div>
      ))}
    </div>
  );
}
```

