```typescript
import { useState } from 'react';
import { formatDistanceToNow } from 'date-fns';
import { Plus, Trash2, Check } from 'lucide-react';
import { Button, Input, Label, Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter } from '@/layers/shared/ui';
import { useMarketplaceSources, useAddMarketplaceSource, useRemoveMarketplaceSource } from '@/layers/entities/marketplace';

/**
 * Marketplace sources management. Lists configured git registries and
 * allows adding/removing sources. Mounted at /marketplace/sources.
 */
export function MarketplaceSourcesView() {
  const { data: sources, isLoading } = useMarketplaceSources();
  const addSource = useAddMarketplaceSource();
  const removeSource = useRemoveMarketplaceSource();
  const [addDialogOpen, setAddDialogOpen] = useState(false);
  const [name, setName] = useState('');
  const [url, setUrl] = useState('');

  const handleAdd = () => {
    addSource.mutate(
      { name: name || undefined, url },
      {
        onSuccess: () => {
          setAddDialogOpen(false);
          setName('');
          setUrl('');
        },
      }
    );
  };

  return (
    <div className="container-default mx-auto space-y-6 py-8">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-semibold tracking-tight">Marketplace Sources</h1>
          <p className="text-sm text-muted-foreground">Add or remove git registries that publish marketplace packages.</p>
        </div>
        <Button onClick={() => setAddDialogOpen(true)}>
          <Plus className="mr-1 size-4" /> Add Marketplace
        </Button>
      </div>

      {isLoading && <p className="text-sm text-muted-foreground">Loading sources...</p>}

      <div className="space-y-3">
        {sources?.map((source) => (
          <div key={source.name} className="rounded-xl border bg-card p-6">
            <div className="flex items-start justify-between">
              <div className="flex items-start gap-3">
                <Check className="mt-0.5 size-5 text-emerald-500" aria-label="Healthy" />
                <div>
                  <h3 className="text-sm font-semibold">{source.name}</h3>
                  <p className="text-xs text-muted-foreground">{source.url}</p>
                  <p className="mt-1 text-xs text-muted-foreground">
                    {source.packageCount} packages • Last refreshed{' '}
                    {formatDistanceToNow(new Date(source.lastRefreshed), { addSuffix: true })}
                  </p>
                </div>
              </div>
              <Button
                variant="ghost"
                size="sm"
                onClick={() => removeSource.mutate(source.name)}
                disabled={removeSource.isPending}
                className="text-destructive"
              >
                <Trash2 className="mr-1 size-3" /> Remove
              </Button>
            </div>
          </div>
        ))}
      </div>

      <Dialog open={addDialogOpen} onOpenChange={setAddDialogOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Add Marketplace Source</DialogTitle>
          </DialogHeader>
          <div className="space-y-3">
            <div>
              <Label htmlFor="source-url">Git URL</Label>
              <Input
                id="source-url"
                value={url}
                onChange={(e) => setUrl(e.target.value)}
                placeholder="github.com/org/marketplace"
              />
            </div>
            <div>
              <Label htmlFor="source-name">Name (optional)</Label>
              <Input
                id="source-name"
                value={name}
                onChange={(e) => setName(e.target.value)}
                placeholder="Auto-detected from URL if blank"
              />
            </div>
          </div>
          <DialogFooter>
            <Button variant="ghost" onClick={() => setAddDialogOpen(false)}>Cancel</Button>
            <Button onClick={handleAdd} disabled={!url || addSource.isPending}>
              {addSource.isPending ? 'Adding...' : 'Add'}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}
