/**
 * @vitest-environment jsdom
 */
import { describe, it, expect, vi, beforeEach } from 'vitest';
import { render, screen, fireEvent, waitFor } from '@testing-library/react';
import { QueryClient, QueryClientProvider } from '@tanstack/react-query';
import { DorkHub } from '../ui/DorkHub';
import { useDorkHubStore } from '../model/dork-hub-store';

const mockListPackages = vi.fn();
const mockGetPackage = vi.fn();
const mockGetPreview = vi.fn();
const mockInstall = vi.fn();
const mockListInstalled = vi.fn();

vi.mock('@/layers/shared/lib/transport', () => ({
  marketplaceMethods: {
    listPackages: (...a: unknown[]) => mockListPackages(...a),
    getPackage: (...a: unknown[]) => mockGetPackage(...a),
    getPermissionPreview: (...a: unknown[]) => mockGetPreview(...a),
    install: (...a: unknown[]) => mockInstall(...a),
    listInstalled: (...a: unknown[]) => mockListInstalled(...a),
  },
}));

vi.mock('sonner', () => ({
  toast: { loading: vi.fn(() => 'id'), success: vi.fn(), error: vi.fn(), dismiss: vi.fn() },
}));

function wrapper({ children }: { children: React.ReactNode }) {
  const qc = new QueryClient({ defaultOptions: { queries: { retry: false } } });
  return <QueryClientProvider client={qc}>{children}</QueryClientProvider>;
}

describe('DorkHub install flow integration', () => {
  beforeEach(() => {
    vi.clearAllMocks();
    useDorkHubStore.setState({ detailPackage: null, installConfirmPackage: null });
    mockListPackages.mockResolvedValue([
      { name: '@test/pkg', type: 'agent', displayName: 'Test Pkg', description: 'A test' },
    ]);
    mockGetPackage.mockResolvedValue({ name: '@test/pkg', displayName: 'Test Pkg', description: 'A test', version: '1.0.0', readme: '# Readme' });
    mockGetPreview.mockResolvedValue({
      fileChanges: [{ path: 'a' }],
      extensions: [],
      tasks: [],
      secrets: [],
      externalHosts: [],
      requires: [],
      conflicts: [],
    });
    mockListInstalled.mockResolvedValue([]);
    mockInstall.mockResolvedValue({ installed: true });
  });

  it('drives browse -> detail -> confirm -> install', async () => {
    render(<DorkHub />, { wrapper });

    // 1. Grid loads
    await waitFor(() => expect(screen.getByText('Test Pkg')).toBeInTheDocument());

    // 2. Click card -> detail sheet opens
    fireEvent.click(screen.getByTestId('package-card-@test/pkg'));
    await waitFor(() => expect(screen.getAllByText('Test Pkg').length).toBeGreaterThan(1));

    // 3. Click Install in sheet -> confirmation dialog opens
    const sheetInstallButton = screen.getAllByRole('button', { name: /install/i })[0];
    fireEvent.click(sheetInstallButton);
    await waitFor(() => expect(screen.getByText(/install test pkg\?/i)).toBeInTheDocument());

    // 4. Confirm install
    const confirmButton = screen.getByRole('button', { name: /^install$/i });
    fireEvent.click(confirmButton);

    await waitFor(() => expect(mockInstall).toHaveBeenCalledWith('@test/pkg', undefined));
  });
});
```

Important: Because `DorkHub` includes `PackageDetailSheet` and `InstallConfirmationDialog`, which in turn use Radix/shadcn portals, you may need to ensure portals render within the test container. Check existing dialog tests in the project for the pattern.

**Marketplace transaction testing rule** (from CLAUDE.md): This test mocks at the HTTP method level, so it does NOT exercise the real `services/marketplace/transaction.ts`. If any future variant of this test invokes server-side flows with `rollbackBranch: true`, it MUST mock `_internal.isGitRepo` in `beforeEach` to return false — otherwise the rollback will destroy uncommitted work. This test doesn't need that mock because it never touches transaction code, but document it in a code comment at the top of the file.

